"use client";

import Image from "next/image";
import { useRouter } from "next/navigation";
import { useMemo, useState } from "react";

type Usulan = {
  id: string;
  esl: string;
  jabatan: string;
  nama: string;
  pktGol: string;
  nrpNip: string;
  createdAt: string;
};

const STORAGE_KEY = "bnn_usulan_v1";

function loadUsulan(): Usulan[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? (JSON.parse(raw) as Usulan[]) : [];
  } catch {
    return [];
  }
}

function saveUsulan(next: Usulan[]) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(next));
}

function uid() {
  // simple id
  return `${Date.now()}_${Math.random().toString(16).slice(2)}`;
}

export default function InputUsulanPage() {
  const router = useRouter();

  const [form, setForm] = useState({
    esl: "",
    jabatan: "",
    nama: "",
    pktGol: "",
    nrpNip: "",
  });

  const disabled = useMemo(() => {
    return (
      !form.esl.trim() ||
      !form.jabatan.trim() ||
      !form.nama.trim() ||
      !form.pktGol.trim() ||
      !form.nrpNip.trim()
    );
  }, [form]);

  function onChange<K extends keyof typeof form>(key: K, value: string) {
    setForm((p) => ({ ...p, [key]: value }));
  }

  function onSubmit(e: React.FormEvent) {
    e.preventDefault();

    // validasi simple
    if (disabled) {
      alert("Mohon lengkapi semua field.");
      return;
    }

    const nextItem: Usulan = {
      id: uid(),
      esl: form.esl.trim(),
      jabatan: form.jabatan.trim(),
      nama: form.nama.trim(),
      pktGol: form.pktGol.trim(),
      nrpNip: form.nrpNip.trim(),
      createdAt: new Date().toISOString(),
    };

    const prev = loadUsulan();
    const next = [nextItem, ...prev]; // terbaru di atas
    saveUsulan(next);

    // reset (opsional)
    setForm({ esl: "", jabatan: "", nama: "", pktGol: "", nrpNip: "" });

    // pindah ke daftar usulan
    router.push("/daftar_usulan");
  }

  return (
    <div className="flex min-h-[calc(100vh-0px)] items-center justify-center px-4 py-10">
      <div className="w-full max-w-[420px]">
        <div className="rounded-md bg-white shadow-[0_18px_55px_rgba(0,0,0,0.14)] ring-1 ring-black/5">
          <div className="px-10 pt-10">
            {/* Logo */}
            <div className="flex justify-center">
              <div className="relative h-16 w-16">
                <Image
                  src="/LogoBNN.png"
                  alt="BNN"
                  fill
                  className="object-contain"
                  priority
                />
              </div>
            </div>

            {/* Title */}
            <h1 className="mt-4 text-center text-sm font-semibold tracking-wide text-zinc-900">
              INPUT USULAN
            </h1>

            {/* Form */}
            <form onSubmit={onSubmit} className="mt-6 space-y-4 pb-10">
              <Field label="ESL" value={form.esl} onChange={(v) => onChange("esl", v)} />
              <Field
                label="Jabatan"
                value={form.jabatan}
                onChange={(v) => onChange("jabatan", v)}
              />
              <Field label="Nama" value={form.nama} onChange={(v) => onChange("nama", v)} />
              <Field
                label="PKT/GOL"
                value={form.pktGol}
                onChange={(v) => onChange("pktGol", v)}
              />
              <Field
                label="NRP/NIP"
                value={form.nrpNip}
                onChange={(v) => onChange("nrpNip", v)}
              />

              <button
                type="submit"
                disabled={disabled}
                className={[
                  "mt-4 w-full rounded-md px-4 py-2.5",
                  "text-xs font-semibold tracking-wide text-white",
                  "shadow-[0_10px_25px_rgba(52,85,143,0.25)] transition",
                  disabled
                    ? "bg-[#34558f]/60 cursor-not-allowed"
                    : "bg-[#34558f] hover:bg-[#2f4c80] active:bg-[#29416e]",
                  "focus:outline-none focus:ring-2 focus:ring-[#34558f]/40 focus:ring-offset-2",
                ].join(" ")}
              >
                SIMPAN
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}

/* =======================
   Reusable Field
======================= */
function Field({
  label,
  value,
  onChange,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
}) {
  return (
    <label className="block">
      <span className="mb-1 block text-[11px] text-zinc-700">{label}</span>
      <input
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className={[
          "h-9 w-full rounded-[4px]",
          "border border-zinc-300 bg-white",
          "px-3 text-sm text-zinc-900",
          "placeholder:text-zinc-400",
          "outline-none transition",
          "focus:border-[#34558f] focus:ring-2 focus:ring-[#34558f]/20",
        ].join(" ")}
      />
    </label>
  );
}
